#!/usr/bin/env python3
"""
Build a truly static/local SFMC quiz file - v64.

New in v25:
1. Changes Test 100 and Quiz 100 into randomized 50-question modes named Test 50 and Quiz 50.
2. Adds a split Top Missed card with separate Top 10 and Top 20 buttons.
3. Updates graph plotting rules to require completed 10-, 20-, or 50-question attempts.
4. Tracks study time only while the page is visible and pauses after 2 minutes without interaction.
5. Cleans up the in-test mode heading/description layout next to the Home button.
6. Color-codes question meta bubbles by saved accuracy: red under 50%, yellow under 75%, green 75%+.
7. Preserves the v19 styling, scroll alignment, mascot, confetti, graph, stats, and localStorage history features.

Run in a-Shell:
  python3 build_sfmc_static_quiz_v64.py

Then run:
  python3 -m http.server 8000

Open Safari:
  http://127.0.0.1:8000/index.html
"""

from __future__ import annotations

import html
import json
import re
import sys
import urllib.request
from html.parser import HTMLParser
from pathlib import Path

SOURCE_URL = "https://mellifluous-kashata-1dfd45.netlify.app/"
READER_URL = "https://r.jina.ai/" + SOURCE_URL

OUT_HTML = Path("index.html")
OUT_JSON = Path("sfmc_question_data.json")
DEBUG_TEXT = Path("page_text_debug.txt")
CELEBRATION_IMAGE_DATA = "data:image/png;base64,"


class PageTextParser(HTMLParser):
    """Very small HTML-to-text parser using only Python's standard library."""

    BLOCK_TAGS = {
        "address", "article", "aside", "blockquote", "br", "div", "dl", "dt",
        "dd", "fieldset", "figcaption", "figure", "footer", "form", "h1",
        "h2", "h3", "h4", "h5", "h6", "header", "hr", "li", "main", "nav",
        "ol", "p", "pre", "section", "table", "tbody", "td", "tfoot", "th",
        "thead", "tr", "ul"
    }

    SKIP_TAGS = {"script", "style", "noscript", "svg"}

    def __init__(self) -> None:
        super().__init__(convert_charrefs=True)
        self.parts: list[str] = []
        self.skip_depth = 0

    def handle_starttag(self, tag: str, attrs) -> None:
        tag = tag.lower()
        if tag in self.SKIP_TAGS:
            self.skip_depth += 1
            return
        if self.skip_depth:
            return
        if tag == "li":
            self.parts.append("\n* ")
        elif tag in self.BLOCK_TAGS:
            self.parts.append("\n")

    def handle_endtag(self, tag: str) -> None:
        tag = tag.lower()
        if tag in self.SKIP_TAGS and self.skip_depth:
            self.skip_depth -= 1
            return
        if self.skip_depth:
            return
        if tag in self.BLOCK_TAGS:
            self.parts.append("\n")

    def handle_data(self, data: str) -> None:
        if not self.skip_depth:
            self.parts.append(data)

    def get_text(self) -> str:
        return "".join(self.parts)


def fetch_url(url: str) -> str:
    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": "Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) AppleWebKit/605.1.15 Safari/604.1",
            "Accept": "text/html,text/plain,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
        },
    )
    with urllib.request.urlopen(req, timeout=60) as response:
        raw = response.read()
        charset = response.headers.get_content_charset() or "utf-8"
    return raw.decode(charset, errors="replace")


def html_to_text(raw: str) -> str:
    if re.search(r"</?[a-zA-Z][^>]*>", raw):
        parser = PageTextParser()
        parser.feed(raw)
        text = parser.get_text()
    else:
        text = raw

    text = html.unescape(text)
    text = text.replace("\r", "\n").replace("\u00a0", " ")
    text = text.replace("“", '"').replace("”", '"').replace("’", "'").replace("‘", "'")
    return text


def get_readable_page_text() -> str:
    """
    Try the reader URL first because it returns the Netlify page as plain readable text.
    Fall back to the original URL if needed.
    """
    attempts = [
        ("Jina Reader readable text", READER_URL),
        ("Original Netlify page", SOURCE_URL),
    ]

    errors = []
    best_text = ""

    for label, url in attempts:
        try:
            print(f"Trying {label}: {url}")
            raw = fetch_url(url)
            text = html_to_text(raw)
            DEBUG_TEXT.write_text(text, encoding="utf-8")

            question_count = len(re.findall(r"\bQuestion\s+\d+\s*:", text, flags=re.I))
            correct_count = len(re.findall(r"\(?\s*Correct\s*\)?", text, flags=re.I))

            print(f"  Found question labels: {question_count}")
            print(f"  Found correct markers: {correct_count}")

            if question_count >= 20 and correct_count >= 20:
                return text

            if len(text) > len(best_text):
                best_text = text

            errors.append(f"{label}: found {question_count} question labels and {correct_count} correct markers")
        except Exception as exc:
            errors.append(f"{label}: {exc}")

    if best_text:
        DEBUG_TEXT.write_text(best_text, encoding="utf-8")

    raise RuntimeError(
        "Could not find the quiz text in the downloaded page.\n"
        + "\n".join(errors)
        + f"\n\nA debug copy was saved to {DEBUG_TEXT}. Run: cat page_text_debug.txt"
    )


def force_parse_line_breaks(text: str) -> str:
    """Force line breaks around structural markers when the source arrives as one long line."""
    text = text.replace("\u00a0", " ")
    text = text.replace("&ast;", "*").replace("\\*", "*")

    text = re.sub(
        r"\s*(Email\s+Specialist\s+Practice\s+Test\s+\d+)",
        r"\n\1\n",
        text,
        flags=re.I,
    )
    text = re.sub(
        r"\s*(Question\s+\d+\s*:)",
        r"\n\1 ",
        text,
        flags=re.I,
    )
    text = re.sub(r"\s+([*•∙●·]\s*)", r"\n\1", text)
    text = re.sub(r"\s*\(?\s*Correct\s*\)?\s*", r"\n(Correct)\n", text, flags=re.I)
    text = re.sub(
        r"\s*(#{0,6}\s*Explanation)\s*",
        r"\n#### Explanation\n",
        text,
        flags=re.I,
    )
    return text


def stable_slug(text: str, length: int = 56) -> str:
    text = html.unescape(text).lower()
    text = re.sub(r"[^a-z0-9]+", "-", text)
    text = re.sub(r"-+", "-", text).strip("-")
    return text[:length].strip("-") or "question"


def section_parse_questions(page_text: str) -> list[dict]:
    """
    Regex parser that does not depend on the page having clean line breaks.
    It splits the whole downloaded text by Question labels, then splits each
    question block by answer bullets and Explanation markers.
    """
    text = html.unescape(page_text)
    text = text.replace("\r", "\n").replace("\u00a0", " ")
    text = text.replace("\\*", "*").replace("&ast;", "*")
    text = text.replace("“", '"').replace("”", '"').replace("’", "'").replace("‘", "'")
    text = re.sub(r"^\s*L\d+\s*:\s*", "", text, flags=re.M)

    q_matches = list(re.finditer(r"\bQuestion\s+(\d+)\s*:", text, flags=re.I))
    questions = []
    current_test_num = 1
    last_q_num = 0

    for i, match in enumerate(q_matches):
        q_num = int(match.group(1))
        if i > 0 and q_num <= last_q_num:
            current_test_num += 1
        last_q_num = q_num

        block = text[match.end(): q_matches[i + 1].start() if i + 1 < len(q_matches) else len(text)]

        exp_match = re.search(r"#{0,6}\s*Explanation\b", block, flags=re.I)
        if exp_match:
            before_exp = block[:exp_match.start()]
            explanation = block[exp_match.end():]
        else:
            before_exp = block
            explanation = ""

        before_exp = re.sub(r"#+\s*!*\s*STUDY AT YOUR OWN RISK\s*!*", " ", before_exp, flags=re.I)
        before_exp = re.sub(r"#+\s*Email\s+Specialist\s+Practice\s+Test\s+\d+", " ", before_exp, flags=re.I)
        # Stop explanations before source-page boilerplate, disclaimers, repeated headings, or footer copy.
        footer_marker = re.compile(
            r"(?:^|\n)\s*(?:#{1,6}\s*)?(?:"
            r"!*\s*STUDY AT YOUR OWN RISK\s*!*|"
            r"Email\s+Specialist\s+Practice\s+Test(?:\s+\d+)?|"
            r"Salesforce\s+Marketing\s+Cloud\s+Email\s+Specialist|"
            r"Practice\s+Test\s+\d+|"
            r"Disclaimer|Copyright|All rights reserved|Source|References?"
            r")\b.*$",
            flags=re.I | re.S,
        )
        explanation = footer_marker.sub("", explanation)
        explanation = re.sub(r"!*\s*STUDY AT YOUR OWN RISK\s*!*.*$", "", explanation, flags=re.I | re.S)

        parts = re.split(r"\s+[*•∙●·]\s+", before_exp)
        if len(parts) < 3:
            parts = re.split(r"(?:^|\n)\s*[*•∙●·]\s+", before_exp)

        question_text = parts[0]
        question_text = re.sub(r"\s+", " ", question_text).strip(" -\n\t")

        options = []
        for raw_option in parts[1:]:
            raw_option = raw_option.strip()
            if not raw_option:
                continue
            correct = bool(re.search(r"\(?\s*Correct\s*\)?", raw_option, flags=re.I))
            option_text = re.sub(r"\(?\s*Correct\s*\)?", " ", raw_option, flags=re.I)
            option_text = re.sub(r"\s+", " ", option_text).strip(" -\n\t")
            if option_text and option_text.lower() != "unattempted":
                options.append({"text": option_text, "correct": correct})

        correct_indexes = [idx for idx, opt in enumerate(options) if opt["correct"]]
        explanation = re.sub(r"\s+", " ", explanation).strip(" -\n\t")

        if question_text and len(options) >= 2 and correct_indexes:
            test_name = f"Practice Test {current_test_num}"
            questions.append({
                "test": test_name,
                "number": q_num,
                "question": question_text,
                "options": options,
                "correctIndexes": correct_indexes,
                "multi": len(correct_indexes) > 1,
                "explanation": explanation,
                "id": f"pt{current_test_num}-q{q_num}-{stable_slug(question_text)}",
            })

    by_key = {}
    for item in questions:
        key = f'{item["test"]}|{item["number"]}'
        old = by_key.get(key)
        quality = len(item["question"]) + len(item["explanation"]) + sum(len(o["text"]) for o in item["options"]) + 100 * len(item["correctIndexes"])
        old_quality = -1 if old is None else len(old["question"]) + len(old["explanation"]) + sum(len(o["text"]) for o in old["options"]) + 100 * len(old["correctIndexes"])
        if old is None or quality > old_quality:
            by_key[key] = item

    return sorted(
        by_key.values(),
        key=lambda item: (
            int(re.search(r"\d+", item["test"]).group(0)) if re.search(r"\d+", item["test"]) else 0,
            item["number"],
        ),
    )


def parse_questions(page_text: str) -> list[dict]:
    questions = section_parse_questions(page_text)
    if questions:
        return questions
    return section_parse_questions(force_parse_line_breaks(page_text))


